static int FindRow(const u32* keys, int stride, int count, u32 usa) {
    int lo = 0, hi = count - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        u32 k = keys[mid * stride];
        if (k == usa)
            return mid;
        if (k < usa)
            lo = mid + 1;
        else
            hi = mid - 1;
    }
    return -1;
}

u32 Port_RemapMapOffset(u32 usa_offset) {
    int row;
    if (gActiveRegion == TMC_REGION_USA)
        return usa_offset;
    row = FindRow(&sMapRemap[0][0], 3, (int)(sizeof(sMapRemap) / sizeof(sMapRemap[0])), usa_offset);
    if (row < 0)
        return usa_offset; /* non-divergent or ROM-native (already correct) */
    return (gActiveRegion == TMC_REGION_EU) ? sMapRemap[row][1] : sMapRemap[row][2];
}

u32 Port_RemapGfxOffset(u32 usa_offset) {
    int row;
    if (gActiveRegion != TMC_REGION_EU)
        return usa_offset; /* JP gfx blob layout == USA */
    row = FindRow(&sGfxRemapEU[0][0], 2, (int)(sizeof(sGfxRemapEU) / sizeof(sGfxRemapEU[0])), usa_offset);
    if (row < 0)
        return usa_offset;
    return sGfxRemapEU[row][1];
}
